record_types.code:
type Context_Type is
   record
      UID   : UID_T;
      GID   : GID_T;
      PID   : PID_T;
      Data  : access User_Data_Type;
   end record;

type File_Info_Type is record
   Flags       : Flags_Type;
   Fh_Old      : Interfaces.C.unsigned_long;
   Writepage   : Interfaces.C.int;
   Direct_IO   : Boolean := True;
   Keep_Cache  : Boolean := True;
   Flush       : Boolean := True;
   Nonseekable : Boolean := True;
   Fh          : File_Access;
   Lock_Owner  : Interfaces.Unsigned_64;
end record;

type Flags_Type(Option : Boolean := True) is
   record case Option is
      when True =>
         RW          : RW_Type;
         O_CREAT     : Boolean;
         O_EXCL      : Boolean;
         O_NOCTTY    : Boolean;
         O_TRUNC     : Boolean;
         O_APPEND    : Boolean;
         O_NONBLOCK  : Boolean;
         O_ASYNC     : Boolean;
         O_DSYNC     : Boolean;
         O_DIRECTORY : Boolean;
         O_NOFOLLOW  : Boolean;
         O_CLOEXEC   : Boolean;
         when False =>
            O_NDELAY    : Boolean;
         end case;
   end record;

type St_Mode_Type is
   record
      S_IFIFO : Boolean;
      S_IFCHR : Boolean;
      S_IFDIR : Boolean;
      S_IFREG : Boolean;
      S_IRUSR : Boolean;
      S_IWUSR : Boolean;
      S_IXUSR : Boolean;
      S_IRGRP : Boolean;
      S_IWGRP : Boolean;
      S_IXGRP : Boolean;
      S_IROTH : Boolean;
      S_IWOTH : Boolean;
      S_IXOTH : Boolean;
      S_ISUID : Boolean;
      S_ISGID : Boolean;
      S_ISVTX : Boolean;
   end record;

type Stat_Type is
   record
      St_Dev     : Dev_T;
      St_Ino     : Ino_T;
      St_Mode    : St_Mode_Type;
      St_Nlink   : NLink_T;
      St_Uid     : Uid_T;
      St_Gid     : Gid_T;
      St_Rdev    : Dev_T;
      St_Size    : Off_T;
      St_Atime   : Time_T;
      St_Mtime   : Time_T;
      St_Ctime   : Time_T;
      St_Blksize : Blksize_T;
      St_Blocks  : Blkcnt_T;
   end record;

